class Solution:
    def nthUglyNumber(self, n, a, b, c):
        from math import gcd
        def lcm(x, y):
            return x // gcd(x, y) * y
        ab, ac, bc = lcm(a, b), lcm(a, c), lcm(b, c)
        abc = lcm(ab, c)
        def cnt(x):
            return x // a + x // b + x // c - x // ab - x // ac - x // bc + x // abc
        x = 0
        seen = 0
        while seen < n:
            x += 1
            if x % a == 0 or x % b == 0 or x % c == 0:
                seen += 1
        return x

