var nthUglyNumber = function(n, a, b, c) {
    const gcd = (x, y) => { while (y) { [x, y] = [y, x % y]; } return x; };
    const lcm = (x, y) => x / gcd(x, y) * y;
    const ab = lcm(a, b), ac = lcm(a, c), bc = lcm(b, c);
    const abc = lcm(ab, c);
    const cnt = (x) => Math.floor(x / a) + Math.floor(x / b) + Math.floor(x / c) - Math.floor(x / ab) - Math.floor(x / ac) - Math.floor(x / bc) + Math.floor(x / abc);
    let lo = 1, hi = 2e9;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (cnt(mid) >= n) hi = mid; else lo = mid + 1;
    }
    return lo;
};
